mapper.select:
select s.*, g.goods_name, g.goods_code, w.warehouse_name, o.owner_name, u.real_name as operator_name from in_stock s left join goods g on s.goods_id=g.goods_id left join warehouse w on s.warehouse_id=w.warehouse_id left join owner o on s.owner_id=o.owner_id left join sys_user u on s.operator_id=u.user_id where 1=1
and g.goods_name like concat('%',#{goodsName},'%')
and g.category_id=#{categoryId}
and s.in_time >= #{startTime}
and s.in_time <= #{endTime}
order by s.in_time desc
